{% extends "base.html" %}

{% block content %}
<link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/css/bootstrap.min.css">
<style>
    :root {
        --primary-color: #667eea;
        --secondary-color: #764ba2;
        --success-color: #10b981;
        --warning-color: #f59e0b;
        --danger-color: #dc3545;
        --light-bg: #f8f9fa;
        --card-shadow: 0 2px 12px rgba(0, 0, 0, 0.08);
        --hover-shadow: 0 8px 24px rgba(0, 0, 0, 0.12);
    }

    body {
        background-color: var(--light-bg);
    }

    .my-posts-container {
        max-width: 800px;
        margin: 0 auto;
        padding: 20px;
    }

    .page-header {
        display: flex;
        justify-content: space-between;
        align-items: center;
        margin-bottom: 40px;
        padding-bottom: 20px;
        border-bottom: 2px solid #e9ecef;
    }

    .page-header h1 {
        font-size: 32px;
        font-weight: 700;
        color: #2d3748;
        margin: 0;
    }

    .btn-create {
        background: linear-gradient(135deg, var(--primary-color) 0%, var(--secondary-color) 100%);
        color: white;
        padding: 12px 20px;
        border-radius: 8px;
        font-weight: 600;
        border: none;
        cursor: pointer;
        transition: all 0.3s ease;
        text-decoration: none;
        display: inline-flex;
        align-items: center;
        gap: 6px;
    }

    .btn-create:hover {
        transform: translateY(-2px);
        box-shadow: 0 5px 20px rgba(102, 126, 234, 0.4);
        color: white;
    }

    .post-card {
        background: white;
        border-radius: 12px;
        padding: 24px;
        margin-bottom: 24px;
        box-shadow: var(--card-shadow);
        transition: all 0.3s ease;
    }

    .post-card:hover {
        box-shadow: var(--hover-shadow);
        transform: translateY(-4px);
    }

    .post-header {
        display: flex;
        align-items: center;
        gap: 12px;
        margin-bottom: 16px;
    }

    .post-author-avatar {
        width: 40px;
        height: 40px;
        border-radius: 50%;
        background: linear-gradient(135deg, var(--primary-color) 0%, var(--secondary-color) 100%);
        display: flex;
        align-items: center;
        justify-content: center;
        color: white;
        font-weight: 700;
        font-size: 16px;
        flex-shrink: 0;
    }

    .post-author-details strong {
        display: block;
        font-size: 15px;
        color: #2d3748;
        margin-bottom: 2px;
    }

    .post-author-details small {
        color: #718096;
        font-size: 12px;
    }

    .post-title {
        font-size: 22px;
        font-weight: 700;
        color: #2d3748;
        margin: 16px 0 12px 0;
        line-height: 1.4;
    }

    .post-content {
        color: #4a5568;
        font-size: 15px;
        line-height: 1.6;
        margin-bottom: 16px;
    }

    .post-category {
        margin-bottom: 12px;
    }

    .category-chip {
        display: inline-block;
        background: #eef2ff;
        color: #4338ca;
        border: 1px solid #c7d2fe;
        font-size: 12px;
        font-weight: 600;
        padding: 5px 10px;
        border-radius: 999px;
    }

    .category-chip.empty {
        background: #f3f4f6;
        color: #4b5563;
        border-color: #e5e7eb;
    }

    .post-stats {
        display: flex;
        gap: 20px;
        color: #718096;
        font-size: 14px;
        padding: 12px 0;
        border-top: 1px solid #e2e8f0;
        border-bottom: 1px solid #e2e8f0;
        margin: 16px 0;
    }

    .post-stat-item {
        display: flex;
        align-items: center;
        gap: 6px;
    }

    .post-stat-item strong {
        color: #2d3748;
    }

    .post-actions {
        display: flex;
        gap: 10px;
        margin: 16px 0;
        flex-wrap: wrap;
    }

    .post-action-btn {
        padding: 10px 14px;
        border: none;
        border-radius: 8px;
        font-size: 14px;
        font-weight: 600;
        cursor: pointer;
        transition: all 0.3s ease;
        display: inline-flex;
        align-items: center;
        justify-content: center;
        gap: 6px;
        text-decoration: none;
    }

    .btn-comment {
        background-color: #e2e8f0;
        color: #4a5568;
    }

    .btn-comment:hover {
        background-color: #cbd5e0;
        transform: translateY(-2px);
    }

    .btn-edit {
        background-color: var(--warning-color);
        color: white;
    }

    .btn-edit:hover {
        background-color: #e59e00;
        transform: translateY(-2px);
    }

    .btn-delete {
        background-color: var(--danger-color);
        color: white;
    }

    .btn-delete:hover {
        background-color: #c82333;
        transform: translateY(-2px);
    }

    .comments-section {
        margin-top: 20px;
        padding-top: 16px;
        border-top: 2px solid #e2e8f0;
    }

    .comments-title {
        font-size: 14px;
        font-weight: 700;
        color: #2d3748;
        margin-bottom: 12px;
        text-transform: uppercase;
        letter-spacing: 0.5px;
    }

    .comment-item {
        background-color: #f7fafc;
        padding: 12px 14px;
        border-radius: 8px;
        margin-bottom: 8px;
        border-left: 3px solid var(--primary-color);
    }

    .comment-author {
        font-weight: 600;
        color: #2d3748;
        font-size: 13px;
        margin-bottom: 4px;
    }

    .comment-text {
        color: #4a5568;
        font-size: 13px;
        line-height: 1.5;
        margin: 0;
    }

    .empty-state {
        text-align: center;
        padding: 60px 20px;
        background: white;
        border-radius: 12px;
        box-shadow: var(--card-shadow);
        color: #718096;
    }

    .empty-state-icon {
        font-size: 48px;
        margin-bottom: 16px;
    }

    .empty-state p {
        font-size: 18px;
        margin: 0;
    }

    .post-badge {
        display: inline-block;
        background-color: var(--primary-color);
        color: white;
        padding: 4px 10px;
        border-radius: 20px;
        font-size: 11px;
        font-weight: 700;
        margin-left: 8px;
        text-transform: uppercase;
        letter-spacing: 0.5px;
    }

    .post-badge.published {
        background-color: var(--success-color);
    }

    .post-badge.draft {
        background-color: #6b7280;
    }

    @media (max-width: 600px) {
        .page-header {
            flex-direction: column;
            align-items: flex-start;
            gap: 16px;
        }

        .page-header h1 {
            font-size: 24px;
        }

        .btn-create {
            width: 100%;
            justify-content: center;
        }

        .post-title {
            font-size: 18px;
        }

        .post-actions {
            gap: 8px;
        }

        .post-action-btn {
            flex: 1;
            justify-content: center;
        }
    }
</style>

<div class="my-posts-container">
    <!-- Page Header -->
    <div class="page-header">
        <h1> My Posts</h1>
        <a href="{% url 'blog:create_post' %}" class="btn-create">
            ➕ Create Post
        </a>
    </div>

    <!-- Posts List -->
    {% for post in posts %}
        <div class="post-card">
            <!-- Post Header with Author -->
            <div class="post-header">
                <div class="post-author-avatar">
                    {{ post.author.username|first|upper }}
                </div>
                <div class="post-author-details">
                    <strong>{{ post.author.username }}</strong>
                    <small>{{ post.created_at|date:"M d, Y" }}</small>
                </div>
                {% if post.is_published %}
                    <span class="post-badge published">Published</span>
                {% else %}
                    <span class="post-badge draft">Draft</span>
                {% endif %}
            </div>

            <!-- Post Content -->
            <h3 class="post-title">{{ post.title }}</h3>
            <div class="post-category">
                {% with primary_categories=post.category.all %}
                    {% if primary_categories %}
                        {% for category in primary_categories %}
                            <span class="category-chip">Category: {{ category.name }}</span>
                        {% endfor %}
                    {% else %}
                        {% with fallback_categories=post.categories.all %}
                            {% if fallback_categories %}
                                {% for category in fallback_categories %}
                                    <span class="category-chip">Category: {{ category.name }}</span>
                                {% endfor %}
                            {% else %}
                                <span class="category-chip empty">Category: Uncategorized</span>
                            {% endif %}
                        {% endwith %}
                    {% endif %}
                {% endwith %}
            </div>
            <p class="post-content">{{ post.content |safe }}</p>

            <!-- Post Stats -->
            <div class="post-stats">
                <div class="post-stat-item">
                    <span></span>
                    <span><strong>{{ post.like_set.count }}</strong> {{ post.like_set.count|pluralize:"Like,Likes" }}</span>
                </div>
                <div class="post-stat-item">
                    <span></span>
                    <span><strong>{{ post.approved_comments.count }}</strong> {{ post.approved_comments.count|pluralize:"Comment,Comments" }}</span>
                </div>
            </div>

            <!-- Post Actions -->
            <div class="post-actions">
                <a href="{% url 'blog:create_comment' post.id %}" class="post-action-btn btn-comment">
                     Comment
                </a>

                <!-- Only show for author -->
                {% if request.user == post.author %}
                    <a href="{% url 'blog:update_post' post.id %}" class="post-action-btn btn-edit">
                        ✏️ Edit
                    </a>

                    <a href="{% url 'blog:delete_post' post.id %}" 
                       class="post-action-btn btn-delete"
                       onclick="return confirm('️ Are you sure you want to delete this post? This action cannot be undone.');">
                        ️ Delete
                    </a>
                {% endif %}
            </div>

            <!-- Comments Section -->
            {% if post.approved_comments.all %}
                <div class="comments-section">
                    <div class="comments-title">Recent Comments</div>
                    {% for comment in post.approved_comments.all|slice:":3" %}
                        <div class="comment-item">
                            <div class="comment-author">{{ comment.user.username }}</div>
                            <p class="comment-text">{{ comment.content }}</p>
                        </div>
                    {% endfor %}
                </div>
            {% endif %}
        </div>
    {% empty %}
        <div class="empty-state">
            <div class="empty-state-icon"></div>
            <p>No posts yet! Start creating your first post.</p>
        </div>
    {% endfor %}
</div>

<script src="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/js/bootstrap.bundle.min.js"></script>
{% endblock %}
